using CollegeManagementSystem.Data;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace CollegeManagementSystem.Controllers;[Route("api/[controller]")][ApiController]public class StudentsController(AppDbContext db) : ControllerBase{    [HttpGet]    public async Task<IActionResult> GetAllStudents()    {        var allStudents = await db.Students.ToListAsync();        return Ok(allStudents);    }}